"""Job queue with dead letter support."""


class JobQueue:
    def __init__(self):
        self._jobs = []
        self._dead_letters = []

    def push(self, job):
        self._jobs.append(job)

    def pop(self):
        return self._jobs.pop(0) if self._jobs else None

    def report_failure(self, job, reason):
        self._dead_letters.append({"job": job, "reason": reason})

    @property
    def dead_letters(self):
        return list(self._dead_letters)

"""Worker module with retry logic and queue integration."""
import time
from src.queue import JobQueue


def process_job(job_id, queue=None, max_retries=3):
    """Process a job with retry. Reports to queue on permanent failure."""
    for attempt in range(max_retries + 1):
        try:
            return {"job_id": job_id, "status": "completed"}
        except Exception as e:
            if attempt == max_retries:
                if queue:
                    queue.report_failure(job_id, str(e))
                raise
            time.sleep(2 ** attempt)


def list_pending():
    return []
